import React, { useEffect, useState } from "react";
import { useDispatch, useSelector } from "react-redux";
import {
  getOverviewKPIs,
  getSalesAnalytics,
  getCustomerAnalytics,
} from "../../features/b2b/b2bSlice";
import { Column, Pie } from "@ant-design/plots";
import { Card, Table, Select, Radio } from "antd";
import { BarChart3, Users, DollarSign, RefreshCw, Trophy } from "lucide-react";

const B2bAnalytics = () => {
  const dispatch = useDispatch();
  const [salesPeriod, setSalesPeriod] = useState("month");
  const [loading, setLoading] = useState(true);

  const fetchAnalyticsData = () => {
    setLoading(true);
    dispatch(getOverviewKPIs());
    dispatch(getSalesAnalytics(salesPeriod));
    dispatch(getCustomerAnalytics()).then(() => setLoading(false));
  };

  useEffect(() => {
    fetchAnalyticsData();
  }, [dispatch, salesPeriod]);

  const { kpis, salesAnalytics, customerAnalytics } = useSelector(
    (state) => state.b2b
  );

  // Sales Trend Chart Data
  const trendData =
    salesAnalytics?.salesTrend?.map((item) => ({
      period: new Date(item.timePeriod).toLocaleDateString("en-US", {
        month: "short",
        year: "2-digit",
        ...(salesPeriod === "day" && { day: "numeric" }),
      }),
      revenue: item.revenue,
    })) || [];

  // Category Sales Data
  const catSalesData =
    salesAnalytics?.categorySales?.map((item) => ({
      category: item.category.replace(/_/g, " "),
      revenue: item.revenue,
    })) || [];

  // Payment terms split
  const paySplitData =
    salesAnalytics?.paymentMethodSales?.map((item) => ({
      method: item.paymentMethod,
      revenue: item.revenue,
    })) || [];

  const topBuyerColumns = [
    {
      title: "Institution",
      dataIndex: "institutionName",
      render: (text, record) => (
        <div className="flex flex-col">
          <span className="font-bold text-slate-800 text-[14px]">
            {text || "Individual Wholesale Buyer"}
          </span>
          <span className="text-[11px] text-slate-400 font-bold uppercase mt-0.5">
            {record.firstname} {record.lastname}
          </span>
        </div>
      ),
    },
    {
      title: "Category",
      dataIndex: "customerType",
      render: (type) => (
        <span className="px-2 py-0.5 rounded bg-slate-50 border border-slate-100 text-[10px] font-black text-slate-500 uppercase">
          {type?.replace(/_/g, " ")}
        </span>
      ),
    },
    {
      title: "Orders placed",
      dataIndex: "ordersCount",
      render: (val) => <span className="font-bold text-slate-700">{val} Orders</span>,
    },
    {
      title: "Total Spend",
      dataIndex: "totalSpend",
      render: (val) => (
        <span className="font-black text-slate-900">
          {parseFloat(val).toLocaleString()} ETB
        </span>
      ),
    },
  ];

  return (
    <div className="space-y-8 pb-12">
      {/* Header */}
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h1 className="text-[28px] font-bold text-slate-900 tracking-tight">
            Wholesale Intelligence
          </h1>
          <p className="text-[15px] text-slate-500 mt-1 font-medium">
            Monitor institutional sales trends, payment cycles, and customer lifetime value.
          </p>
        </div>

        <button
          onClick={fetchAnalyticsData}
          disabled={loading}
          className="p-3 bg-white border border-slate-200 rounded-2xl hover:bg-slate-50 transition-all shadow-sm flex items-center gap-2 font-bold text-slate-600 text-xs uppercase tracking-widest"
        >
          <RefreshCw size={16} className={loading ? "animate-spin" : ""} />
          REFRESH INTEL
        </button>
      </div>

      {/* Analytics KPI Dashboard cards */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
        {[
          {
            label: "Gross Sales Volume",
            val: kpis?.sales?.totalRevenue?.toLocaleString() || "0",
            unit: "ETB",
            icon: <DollarSign size={22} />,
            color: "blue",
          },
          {
            label: "Credit Utilization",
            val: kpis?.sales?.creditRevenue?.toLocaleString() || "0",
            unit: `Outstanding Credit`,
            icon: <BarChart3 size={22} />,
            color: "indigo",
          },
          {
            label: "Buyer Segment Count",
            val: customerAnalytics?.customerTypes?.length || "0",
            unit: "Demographics",
            icon: <Users size={22} />,
            color: "emerald",
          },
          {
            label: "Procurement Orders",
            val: kpis?.sales?.totalOrders || "0",
            unit: "Total Placed",
            icon: <Trophy size={22} />,
            color: "amber",
          },
        ].map((k, i) => (
          <div className="kpi-card-premium relative overflow-hidden" key={i}>
            <div
              className={`w-10 h-10 rounded-xl flex items-center justify-center bg-${k.color}-50 text-${k.color}-600 mb-4`}
            >
              {k.icon}
            </div>
            <p className="text-[11px] font-black text-slate-400 uppercase tracking-widest mb-1">
              {k.label}
            </p>
            <span className="text-2xl font-black text-slate-900 tracking-tight">
              {k.val}
            </span>
            <p className="text-[10px] font-bold text-slate-400 mt-1 uppercase tracking-wider">
              {k.unit}
            </p>
          </div>
        ))}
      </div>

      <div className="grid grid-cols-1 xl:grid-cols-3 gap-8">
        {/* Sales Trend Chart */}
        <div className="xl:col-span-2 enterprise-card p-8 bg-white border border-slate-100">
          <div className="flex justify-between items-center mb-8 flex-wrap gap-4">
            <h3 className="text-lg font-black text-slate-900">Institutional Sales Trend</h3>
            <Radio.Group
              value={salesPeriod}
              onChange={(e) => setSalesPeriod(e.target.value)}
              optionType="button"
              buttonStyle="solid"
            >
              <Radio.Button value="day">Day</Radio.Button>
              <Radio.Button value="week">Week</Radio.Button>
              <Radio.Button value="month">Month</Radio.Button>
            </Radio.Group>
          </div>
          <div className="h-[320px]">
            {trendData.length > 0 ? (
              <Column
                data={trendData}
                xField="period"
                yField="revenue"
                color="#3b82f6"
                padding="auto"
                columnStyle={{ radius: [8, 8, 0, 0] }}
              />
            ) : (
              <div className="h-full flex items-center justify-center text-slate-400 font-bold text-sm">
                No Sales Trend Data
              </div>
            )}
          </div>
        </div>

        {/* Commercial Billing Split */}
        <div className="enterprise-card p-8 bg-white border border-slate-100">
          <h3 className="text-lg font-black text-slate-900 mb-8">Cash vs Credit Billing</h3>
          <div className="h-[320px]">
            {paySplitData.length > 0 ? (
              <Pie
                data={paySplitData}
                angleField="revenue"
                colorField="method"
                radius={0.8}
                innerRadius={0.5}
                padding="auto"
                legend={{ position: "bottom" }}
              />
            ) : (
              <div className="h-full flex items-center justify-center text-slate-400 font-bold text-sm">
                No Billing Split Data
              </div>
            )}
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 xl:grid-cols-3 gap-8">
        {/* Top Buyers */}
        <div className="xl:col-span-2 enterprise-card p-8 bg-white border border-slate-100">
          <h3 className="text-lg font-black text-slate-900 mb-6">Top Institutional Buyers</h3>
          <Table
            columns={topBuyerColumns}
            dataSource={customerAnalytics?.topBuyers || []}
            pagination={false}
            className="modern-table"
            rowKey="id"
          />
        </div>

        {/* Demographics Category counts */}
        <div className="enterprise-card p-8 bg-white border border-slate-100">
          <h3 className="text-lg font-black text-slate-900 mb-6">Institution Breakdown</h3>
          <div className="space-y-4">
            {customerAnalytics?.customerTypes?.map((c, idx) => (
              <div key={idx} className="flex justify-between items-center p-3 rounded-2xl bg-slate-50 border border-slate-100">
                <span className="font-bold text-slate-800 text-xs uppercase tracking-wider">
                  {c.customerType.replace(/_/g, " ")}
                </span>
                <span className="font-black text-sm text-slate-900">
                  {c.count} Accounts
                </span>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
};

export default B2bAnalytics;
